INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ZENITH_1: Le email reply detection intelligence: reponse positive (merci, interesse, super) → auto-update CRM hot + notifier commercial. Reponse negative → stop sequence + tag raison.', 'Email reply: positive→CRM hot+notif. Negative→stop+tag raison', 'email', 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_2: Le commercial proposal structure: page 1=recap probleme (montrer ecoute), page 2=solution (comment), page 3=resultats attendus (chiffres), page 4=prix+ROI, page 5=next steps.', 'Proposal 5 pages: probleme + solution + resultats + prix ROI + next steps', 'commercial', 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_3: Le content trend surfing protocol: detecter trend < 24h → creer contenu adapte en 2h → publier → surfer la vague. Apres 72h la trend est morte.', 'Trend surfing: detecter < 24h → creer 2h → publier. > 72h = mort', 'content', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_4: Le SEO cannibalization detection: si 2+ pages ciblent le meme mot-cle et fluctuent en ranking, elles se cannibalisent. Fusionner en 1 page + 301 redirect.', 'SEO cannibalization: 2+ pages meme keyword fluctuent → fusionner + 301', 'seo', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_5: Le ad conversion lag analysis: certaines conversions arrivent 7-14 jours apres le clic. Attendre la fenetre d attribution complete avant de juger une campagne.', 'Conversion lag: attendre fenetre attribution (7-14j) avant juger campagne', 'ads', 'insight', 0.82, 'zenith', 'system'),
('ZENITH_6: Le DM Instagram comment-first strategy: commenter sur 5 posts du prospect avec de la valeur AVANT d envoyer le DM. Il vous reconnait deja.', 'DM comment-first: 5 commentaires valeur avant DM = prospect vous reconnait', 'dm_instagram', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_7: Le WhatsApp interactive message buttons: les messages avec boutons (Quick Reply, CTA) ont 40% plus de clics que les messages texte seuls.', 'WhatsApp boutons interactifs = +40% clics vs texte seul', 'whatsapp', 'insight', 0.82, 'zenith', 'system'),
('ZENITH_8: Le chatbot sentiment pivot: si le sentiment passe de positif a negatif dans la meme conversation → escalader immediatement. Le client est frustre.', 'Chatbot sentiment pivot positif→negatif = escalader immediatement', 'chatbot', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_9: Le GMaps review syndication: les avis positifs de Google doivent etre repostes sur le site web (section temoignages), les reseaux sociaux et les emails. Maximum de mileage.', 'GMaps avis → site + social + email. Maximum de mileage par avis', 'gmaps', 'best_practice', 0.80, 'zenith', 'system'),
('ZENITH_10: Le TikTok series strategy: creer une serie (Partie 1, 2, 3...) sur un sujet. Les series generent 3x plus de follows car les viewers veulent la suite.', 'TikTok series parties 1,2,3 = 3x follows (attente suite)', 'tiktok_comments', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_11: Le CEO resource allocation dynamic: si un canal performe 2x mieux que les autres → reallouer 30% du budget des canaux faibles vers le fort. Revisiter mensuellement.', 'CEO allocation: canal 2x meilleur → +30% budget des faibles. Mensuel', 'ceo', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_12: Le retention product adoption curve: J1-7 core feature, J8-14 secondary features, J15-30 advanced features, J30+ power user features. Guider progressivement.', 'Adoption curve: J1-7 core, J8-14 secondary, J15-30 advanced, J30+ power', 'retention', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_13: Le onboarding success prediction: si le client complete les 3 premieres etapes dans les 48h, la probabilite de retention J30 est de 85%.', 'Onboarding prediction: 3 etapes en 48h = 85% retention J30', 'onboarding', 'insight', 0.82, 'zenith', 'system'),
('ZENITH_14: Le comptable monthly close process: reconciliation bancaire → accruals → revenue recognition → expense categorization → P&L → cash flow statement. Chaque mois D+5.', 'Monthly close: reconcil → accruals → revenue → expenses → P&L → cashflow. D+5', 'comptable', 'best_practice', 0.80, 'zenith', 'system'),
('ZENITH_15: Le RH employee engagement drivers top 5: 1) meaning/purpose, 2) growth/development, 3) management quality, 4) recognition, 5) work-life balance.', 'Engagement drivers: meaning + growth + management + recognition + balance', 'rh', 'insight', 0.82, 'zenith', 'system'),
('ZENITH_16: Le marketing brand moment strategy: identifier les 10 moments cles de l annee pour le secteur du client et preparer du contenu 4 semaines avant chaque moment.', 'Brand moments: 10 moments cles/an par secteur. Preparer 4 semaines avant', 'marketing', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_17: Le cross-agent handoff protocol: quand un agent transfere un prospect a un autre agent, le contexte complet doit etre transmis (historique, score, dernier echange, preferences).', 'Handoff cross-agent: transmettre historique + score + echange + preferences', NULL, 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_18: Le customer cohort LTV analysis: mesurer le LTV par cohorte d inscription (par mois). Si le LTV diminue sur les cohortes recentes → probleme d onboarding ou de ciblage.', 'Cohort LTV: LTV par mois inscription. Diminue = probleme onboarding/ciblage', NULL, 'insight', 0.85, 'zenith', 'system'),
('ZENITH_19: Le KeiroAI agent reliability target: chaque agent doit avoir un taux de succes > 95% sur ses executions. < 90% = investigation + fix urgent.', 'Agent reliability: > 95% succes. < 90% = investigation + fix urgent', NULL, 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_20: Le KeiroAI client success framework: onboarding < 5min → first result < 48h → ROI mesurable < 30j → advocacy < 90j.', 'Client success: onboarding <5min → result <48h → ROI <30j → advocacy <90j', 'ceo', 'best_practice', 0.90, 'zenith', 'system'),
('ZENITH_21: Le email bounce prevention: verifier chaque adresse avec un service de verification (ZeroBounce, NeverBounce) AVANT d envoyer. Bounce rate cible < 1%.', 'Email verification pre-envoi: ZeroBounce/NeverBounce. Bounce < 1%', 'email', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_22: Le commercial time management: 60% du temps sur les deals > 50% probabilite, 30% sur les 25-50%, 10% sur les < 25%. Ne pas gaspiller sur les morts.', 'Commercial time: 60% deals >50% proba, 30% 25-50%, 10% <25%', 'commercial', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_23: Le content AB testing system: pour chaque post, preparer 2 versions du hook. Publier la version A → si engagement < seuil → publier version B le lendemain.', 'Content A/B: 2 hooks. A publie → si engagement faible → B le lendemain', 'content', 'best_practice', 0.80, 'zenith', 'system'),
('ZENITH_24: Le SEO competitor backlink analysis: identifier d ou les concurrents obtiennent leurs backlinks → contacter les memes sites avec un meilleur contenu.', 'SEO competitor backlinks: identifier sources concurrents → contacter avec meilleur contenu', 'seo', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_25: Le ad landing page alignment score: 1) meme headline ad/landing, 2) meme offre, 3) meme visuel, 4) CTA clair, 5) vitesse < 2s. Score 5/5 = conversion max.', 'Landing alignment: headline + offre + visuel + CTA + vitesse. 5/5 = conversion max', 'ads', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_26: Le DM conversion science: le DM qui pose une question ouverte liee au business du prospect (comment gerez-vous X?) obtient 3x plus de reponses qu un pitch.', 'DM question ouverte business = 3x reponses vs pitch', 'dm_instagram', 'insight', 0.85, 'zenith', 'system'),
('ZENITH_27: Le WhatsApp abandoned cart sequence: message 1h apres (rappel + image produit) → 24h (urgence + stock faible) → 72h (offre -10%). Recupere 15-25%.', 'WhatsApp cart: 1h rappel → 24h urgence → 72h -10% = 15-25% recuperation', 'whatsapp', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_28: Le chatbot user testing: faire tester le chatbot par 10 personnes non-techniques. Les 5 premieres minutes revelent 80% des problemes d UX conversationnelle.', 'Chatbot testing: 10 non-tech × 5 min = 80% problemes UX', 'chatbot', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_29: Le GMaps attribute optimization: renseigner TOUS les attributs (wifi, parking, accessibilite, paiements acceptes, langues). Les fiches completes ont 2x plus de conversions.', 'GMaps attributs complets = 2x conversions', 'gmaps', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_30: Le TikTok educational content formula: probleme courant (hook) → explication simple (valeur) → solution actionable (CTA) → resultat visible (proof). 15-30s max.', 'TikTok edu: probleme → explication → solution → resultat. 15-30s', 'tiktok_comments', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_31: Le CEO client communication principle: pas de jargon technique. Parler en termes de resultats business (plus de clients, plus de CA, moins de temps gaspille).', 'CEO comm client: resultats business (clients, CA, temps). 0 jargon technique', 'ceo', 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_32: Le retention upsell timing science: le moment optimal pour proposer un upgrade est juste APRES que le client ait obtenu un resultat positif avec le produit.', 'Upsell timing: juste apres resultat positif = moment optimal', 'retention', 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_33: Le onboarding email personalization: adapter le contenu de chaque email d onboarding au type de commerce du client (restaurant reçoit des exemples food, coach des exemples coaching).', 'Onboarding email: adapter exemples au type commerce client', 'onboarding', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_34: Le comptable break-even analysis: calculer le nombre de clients necessaires pour couvrir les couts fixes + variables. En dessous = perte. Au-dessus = profit.', 'Break-even: nombre clients pour couvrir fixes + variables. Au-dessous = perte', 'comptable', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_35: Le RH knowledge management: chaque depart d employe doit inclure un transfert de connaissances de 1 semaine (documentation, formations, handoff projets).', 'Knowledge management: depart = transfert 1 sem (docs, formations, handoff)', 'rh', 'best_practice', 0.80, 'zenith', 'system'),
('ZENITH_36: Le marketing PR strategy: pitcher 1 article/mois a un media pertinent (TechCrunch, Journal du Net, Maddyness). 1 mention presse = +40% credibilite.', 'PR: 1 article/mois media pertinent. 1 mention = +40% credibilite', 'marketing', 'insight', 0.78, 'zenith', 'system'),
('ZENITH_37: Le agent quality gate: chaque output d agent (email, post, DM) passe par un check qualite: brand voice ok? factuel? sans erreur? ton adapte? Si echec → regenerer.', 'Quality gate: brand voice + factuel + sans erreur + ton. Echec = regenerer', NULL, 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_38: Le customer segmentation by intent: ready to buy (prix, demo, trial) vs researching (education, comparaison) vs browsing (curiosite). Adapter le message.', 'Segmentation intent: buy (offre) vs research (education) vs browse (curiosite)', NULL, 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_39: Le KeiroAI intelligence network effect: 1000 clients × 17 agents × 10 actions/jour = 170 000 data points/jour. Chaque jour le systeme devient plus intelligent.', 'KeiroAI network: 1000 clients × 17 agents × 10 actions = 170K datapoints/jour. Plus intelligent chaque jour', NULL, 'insight', 0.90, 'zenith', 'system'),
('ZENITH_40: Le KeiroAI agent collaboration model: contenu attire → SEO positionne → ads amplifie → email nurture → DM qualifie → commercial close → retention garde → CEO coordonne.', 'Agent collab: contenu→SEO→ads→email→DM→commercial→retention→CEO', NULL, 'best_practice', 0.92, 'zenith', 'system'),
('ZENITH_41: Le email campaign seasonality FR: janvier=resolutions, fevrier=SV, mars=printemps, mai=fete meres, juin=soldes, sept=rentree, nov=BF, dec=noel. Anticiper 4 semaines.', 'Email seasonality FR: jan resolutions, fev SV, mai meres, sept rentree, nov BF, dec noel', 'email', 'best_practice', 0.80, 'zenith', 'system'),
('ZENITH_42: Le commercial multi-threading mastery: contacter 3-5 stakeholders dans le meme compte simultanement. Si 1 champion part, le deal survit. +40% win rate.', 'Multi-threading: 3-5 stakeholders meme compte. Si 1 part = deal survit. +40% win rate', 'commercial', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_43: Le content authority positioning: publier 1 article d expertise long (3000+ mots) par mois sur un sujet cle. En 6 mois = reconnu comme expert du sujet.', 'Authority: 1 article 3000+ mots/mois × 6 mois = expert reconnu', 'content', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_44: Le SEO AI overview optimization: structurer le contenu en Q&A, utiliser des listes a puces, citer des sources autoritaires. Etre cite dans la reponse IA Google.', 'SEO AI overview: Q&A + listes + sources = etre cite dans reponse IA Google', 'seo', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_45: Le ad scaling golden rule: ne jamais augmenter le budget de plus de 20% par jour. Au-dela, l algorithme re-entre en learning phase et les performances chutent.', 'Scaling: max +20%/jour. Au-dela = learning phase = performance chute', 'ads', 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_46: Le DM Instagram qualification rapide: 2 questions suffisent: 1) Quel est votre plus gros defi en ce moment? 2) Qu avez-vous essaye pour le resoudre? Si les 2 reponses = fit → proposer RDV.', 'DM qualification: 2 questions (defi + essaye). Fit → RDV', 'dm_instagram', 'best_practice', 0.85, 'zenith', 'system'),
('ZENITH_47: Le WhatsApp business etiquette: toujours se presenter, toujours proposer l opt-out, ne jamais envoyer apres 20h, repondre dans les 5 min pendant les heures ouvrables.', 'WhatsApp etiquette: se presenter + opt-out + pas apres 20h + repondre 5 min', 'whatsapp', 'best_practice', 0.88, 'zenith', 'system'),
('ZENITH_48: Le chatbot continuous improvement cycle: analyser conversations echouees (lundi) → ajouter FAQ (mardi) → tester (mercredi) → deployer (jeudi) → mesurer (vendredi).', 'Chatbot improvement cycle: analyser lun → FAQ mar → test mer → deploy jeu → mesurer ven', 'chatbot', 'best_practice', 0.82, 'zenith', 'system'),
('ZENITH_49: Le GMaps virtual tour integration: ajouter une visite virtuelle 360° sur la fiche Google augmente le temps de consultation de 3x et les conversions de 25%.', 'GMaps visite virtuelle 360° = 3x consultation +25% conversions', 'gmaps', 'insight', 0.80, 'zenith', 'system'),
('ZENITH_50: Le TikTok analytics mastery: les 3 metriques qui determinent la viralite: 1) taux de completion > 50%, 2) taux de partage > 2%, 3) taux de commentaire > 1%.', 'TikTok viralite: completion >50% + partage >2% + commentaire >1%', 'tiktok_comments', 'insight', 0.85, 'zenith', 'system')
